-- Comparações básicas
SELECT * FROM Produtos WHERE Preco > 100;
SELECT * FROM Clientes WHERE Cidade = 'São Paulo';
SELECT * FROM Pedidos WHERE Status <> 'Cancelado';

-- Operadores lógicos
SELECT * FROM Produtos
WHERE Preco > 50 AND Estoque > 0;

SELECT * FROM Clientes
WHERE Cidade = 'São Paulo' OR Cidade = 'Campinas';

-- BETWEEN — intervalo inclusivo
SELECT * FROM Pedidos
WHERE DataPedido BETWEEN '2024-01-01' AND '2024-12-31';

-- IN — lista de valores
SELECT * FROM Clientes
WHERE Cidade IN ('São Paulo', 'Rio de Janeiro', 'Curitiba');

-- LIKE — padrão de texto
SELECT * FROM Clientes WHERE Nome LIKE 'Ana%';  -- começa com Ana
SELECT * FROM Emails WHERE Endereco LIKE '%@gmail.com'; -- termina com

